from __future__ import annotations
import functools
import logging
import threading
from typing import Any, Callable, Iterator, Protocol, Set

class BenchmarkHook(Protocol):
    def on_call_start(layer: str, plugin_name: str, method: str, args: tuple, kwargs: dict) -> Any: ...
    def on_call_end(context: Any, result: Any, error: Exception | None) -> None: ...


class CachingHook(Protocol):
    def get_cached_result(layer: str, plugin_name: str, method: str, args: tuple, kwargs: dict) -> Any: ...
    def cache_result(layer: str, plugin_name: str, method: str, args: tuple, kwargs: dict, result: Any) -> None: ...


class TokenUsageTracker:
    def __init__(self):
        self._usage_by_method: dict[str, list[dict[str, int]]] = {}
        self._lock = threading.Lock()

    def add_usage(self, method_name: str, usage_data: dict[str, int]):
        with self._lock:
            if method_name not in self._usage_by_method:
                self._usage_by_method[method_name] = []
            self._usage_by_method[method_name].append(usage_data)

    def get_total_usage(self) -> dict[str, int]:
        total: dict[str, int] = {}
        for method_usages in self._usage_by_method.values():
            for usage in method_usages:
                for key, value in usage.items():
                    if key not in total:
                        total[key] = 0
                    total[key] += value
        return total


