unregister_hook: Callable[[BenchmarkHook], None]
clear_hooks: Callable[[], None]
has_hooks: Callable[[], bool]
get_hooks: Callable[[], list[BenchmarkHook]]


class InstrumentedProxy:
    def __init__(self, target: Any, layer: str, plugin_name: str, methods_to_track: set[str] | None = None):
        self._target = target
        self._layer = layer
        self._plugin_name = plugin_name
        self._methods_to_track = methods_to_track or set()
        # Initialize token usage tracker for this proxy instance
        self._token_tracker = TokenUsageTracker()

    def __getattr__(self, name: str) -> Any:
        attr = getattr(self._target, name)
        if name in self._methods_to_track and callable(attr):
            return self._wrap_method(attr, name)
        return attr

    def _wrap_method(self, method: Callable, method_name: str) -> Callable:
        @functools.wraps(method)
        def wrapper(*args: Any, **kwargs: Any) -> Any:
            context = None
            error = None
            try:
                # Call the original method
                result = method(*args, **kwargs)

                # Check if this is a token-aware provider and extract usage data
                if hasattr(result, 'get') and isinstance(result.get('usage'), dict):
                    self._token_tracker.add_usage(method_name, result['usage'])
                elif hasattr(result, 'usage') and isinstance(getattr(result, 'usage'), dict):
                    # For protocols returning structured results with usage field
                    self._token_tracker.add_usage(method_name, result.usage)

                return result
            except Exception as e:
                error = e
                raise
            finally:
                pass  # Add timing instrumentation if needed
        return wrapper

    def __repr__(self) -> str:
        return f'InstrumentedProxy({self._target!r})'

    def __str__(self) -> str:
        return self.__repr__()


def maybe_wrap(target: Any, layer: str, plugin_name: str, methods_to_track: set[str] | None = None) -> Any:
    if hasattr(target, '__class__') and hasattr(target.__class__, '_instrumented'):
        return target  # Already instrumented

    # Add the instrumentation
    proxy = InstrumentedProxy(target, layer, plugin_name, methods_to_track)
    setattr(proxy, '_instrumented', True)
    return proxy

def wrap(target: Any, layer: str, plugin_name: str, methods_to_track: set[str] | None = None) -> InstrumentedProxy:
    return InstrumentedProxy(target, layer, plugin_name, methods_to_track)

